// Build context from matched notes
let context = '';
let sources = [];

results.forEach((item, index) => {
  const note = item.json;
  context += `Note ${index + 1} (similarity: ${(note.similarity * 100).toFixed(0)}%):\n${note.content}\n\n`;
  sources.push(`Note ${index + 1}: ${note.content.substring(0, 80)}...`);
});

if (!context) {
  context = 'No clinical notes found for this patient.';
}

const systemPrompt = `You are a clinical AI assistant helping a doctor 
review a patient's medical history. You answer questions based ONLY on 
the clinical notes provided. Be concise, accurate, and medically precise.
Always highlight any allergies or drug interactions if relevant.
If the information is not in the notes, say so clearly — do not guess.`;

const userPrompt = `Patient clinical notes:
${context}

Doctor's question: ${question}

Please provide a clear, concise answer based only on the notes above.
End your answer with a "Sources:" section listing which notes you used.`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt:   userPrompt,
    sources:       sources,
    question:      question,
    context_found: results.length > 0
  }
}];

