parameters.jsCode:
const patients    = $('Total Patients').all();
const visits      = $('Total Visits').all();
const appointments = $('All Appointments').all();
const notifications = $('Total Notifications').all();
const embeddedNotes = $('Embedded Notes').all().filter(i => i.json.embedding !== null && i.json.embedding !== undefined);
const recentActivity = $('Recent Activity').all();

// ── Date helpers ──────────────────────────────────
const now = new Date();
const startOfWeek = new Date(now);
startOfWeek.setDate(now.getDate() - now.getDay());
startOfWeek.setHours(0, 0, 0, 0);

const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const today = now.toISOString().split('T')[0];

// ── Patient stats ─────────────────────────────────
const totalPatients = patients.length;
const newThisMonth = patients.filter(p => 
  new Date(p.json.created_at) >= startOfMonth
).length;

// ── Appointment stats ─────────────────────────────
const allAppts = appointments.map(a => a.json);

const todayAppts = allAppts.filter(a => {
  // We need slot date — approximate from created_at
  return a.status !== 'cancelled';
}).length;

const weekBooked = allAppts.filter(a => 
  new Date(a.booked_at) >= startOfWeek
).length;

const weekAttended = allAppts.filter(a => 
  new Date(a.booked_at) >= startOfWeek && 
  a.status === 'completed'
).length;

const weekCancelled = allAppts.filter(a => 
  new Date(a.booked_at) >= startOfWeek && 
  a.status === 'cancelled'
).length;

const weekUrgent = allAppts.filter(a => 
  new Date(a.booked_at) >= startOfWeek && 
  a.urgent_flag === true
).length;

const totalUrgent = allAppts.filter(a => 
  a.urgent_flag === true && 
  a.status !== 'cancelled'
).length;

// ── Visit stats ───────────────────────────────────
const totalVisits = visits.length;

// ── Diagnosis breakdown ───────────────────────────
const diagnosisMap = {};
visits.forEach(v => {
  const dx = v.json.diagnosis;
  if (dx) diagnosisMap[dx] = (diagnosisMap[dx] || 0) + 1;
});
const diagnosisBreakdown = Object.entries(diagnosisMap)
  .map(([name, value]) => ({ name, value }))
  .sort((a, b) => b.value - a.value)
  .slice(0, 8);

// ── Blood group distribution ──────────────────────
const bloodMap = {};
patients.forEach(p => {
  const bg = p.json.blood_group;
  if (bg) bloodMap[bg] = (bloodMap[bg] || 0) + 1;
});
const bloodGroups = Object.entries(bloodMap)
  .map(([group, count]) => ({ group, count }))
  .sort((a, b) => b.count - a.count);

// ── Monthly registrations (last 6 months) ─────────
const monthMap = {};
patients.forEach(p => {
  const d = new Date(p.json.created_at);
  const key = d.toLocaleDateString('en-GB', { month: 'short', year: 'numeric' });
  monthMap[key] = (monthMap[key] || 0) + 1;
});
const registrationTrend = Object.entries(monthMap)
  .map(([month, patients]) => ({ month, patients }))
  .slice(-6);

// ── Weekly appointment trend (last 7 weeks) ────────
const weekTrend = [];
for (let i = 6; i >= 0; i--) {
  const weekStart = new Date(startOfWeek);
  weekStart.setDate(weekStart.getDate() - (i * 7));
  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekEnd.getDate() + 7);

  const label = `W${7 - i}`;
  const booked = allAppts.filter(a => {
    const d = new Date(a.booked_at);
    return d >= weekStart && d < weekEnd;
  }).length;
  const attended = allAppts.filter(a => {
    const d = new Date(a.booked_at);
    return d >= weekStart && d < weekEnd && a.status === 'completed';
  }).length;
  const cancelled = allAppts.filter(a => {
    const d = new Date(a.booked_at);
    return d >= weekStart && d < weekEnd && a.status === 'cancelled';
  }).length;

  weekTrend.push({ week: label, booked, attended, cancelled });
}

// ── Urgent cases today ────────────────────────────
const urgentRaw = $('Get Urgent Cases Today').all();

const urgentToday = urgentRaw.map(a => ({
  appointment_id: a.json.appointment_id,
  patients:      a.json.full_name,
  symptom:        a.json.symptom,
  time:           a.json.slot_time 
    ? a.json.slot_time.substring(0, 5) // formats "09:00:00" → "09:00"
    : 'N/A',
  status:         a.json.status
}));

// ── Recent activity ───────────────────────────────
const activity = recentActivity.map(n => ({
  type: n.json.type,
  message: n.json.message.substring(0, 80),
  time: new Date(n.json.sent_at).toLocaleTimeString('en-GB', {
    hour: '2-digit', minute: '2-digit'
  })
}));

// ── Gender distribution ───────────────────────────
const genderMap = {};
patients.forEach(p => {
  const g = p.json.gender || 'unknown';
  genderMap[g] = (genderMap[g] || 0) + 1;
});
const genderDistribution = Object.entries(genderMap)
  .map(([gender, count]) => ({ gender, count }));

// ── Top allergies ─────────────────────────────────
const allergyMap = {};
patients.forEach(p => {
  const al = (p.json.allergies || '').trim();
  if (al && al.toLowerCase() !== 'none known' && al.toLowerCase() !== 'none') {
    allergyMap[al] = (allergyMap[al] || 0) + 1;
  }
});
const topAllergies = Object.entries(allergyMap)
  .map(([allergy, count]) => ({ allergy, count }))
  .sort((a, b) => b.count - a.count)
  .slice(0, 5);

// ── RAG stats ─────────────────────────────────────
const embeddingsIndexed = embeddedNotes.length;

// ── Final payload ─────────────────────────────────
const payload = {
  // Overview
  totalPatients,
  newThisMonth,
  todayAppointments: todayAppts,
  totalVisits,
  notificationsSent: notifications.length,
  embeddingsIndexed,

  // Appointments
  weekBooked,
  weekAttended,
  weekCancelled,
  weekUrgent,
  totalUrgent,
  appointmentTrend: weekTrend,
  urgentToday,

  // Patients
  registrationTrend,
  bloodGroups,
  genderDistribution,
  topAllergies,

  // Clinical
  diagnosisBreakdown,
  soapNotesSaved: totalVisits,
  ragModel: 'GPT-4o',
  embeddingModel: 'text-embedding-3-small',
  vectorDimensions: 1536,
  matchCount: 5,
  vectorStore: 'Supabase pgvector',

  // Meta
  generatedAt: new Date().toISOString()
};

return [{ json: payload }];
